766	\section{\v{C}ech acyclicity and vanishing on affines}
767	\label{sec:cech_acyclicity}
768	
769	This section builds the instance-driven pipeline that converts Čech acyclicity of a cover into the vanishing of $H^{\prime n}(U, \mathcal F)$ on affine opens. The engine is the extra-degeneracy contraction for basic-open covers, developed in Sections~\ref{sec:basic_open_infrastructure}--\ref{sec:basic_open_acyclicity}.
770	
771	\subsection{Top-supremum transport}
772	
773	When a cover $\mathfrak U$ is Čech-acyclic and its supremum is the whole space, the vanishing of Čech cohomology transports to the vanishing of whole-space cohomology.
774	
775	\begin{theorem}\leanok
776	[Top-supremum transport, abstract sheaf form]
777	  \label{thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top}
778	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule_of_isCechAcyclicCover_top}
779	  \uses{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover, def:Scheme_HModule_prime_eq_HModule_linearEquiv, def:Scheme_HModule, def:Scheme_HModule_prime}
780	  Let $\mathfrak U$ be a Čech-acyclic cover with $\bigsqcup_i \mathfrak U_i = \top$, and assume a comparison isomorphism between Čech and derived cohomology. For $n \ge 1$, the type $H^{n}(X, \mathcal F)$ is a subsingleton.
781	\end{theorem}
782	
783	\begin{proof}
784	
785	
786	\leanok
787	  The Čech-acyclic consumer gives a subsingleton on $H^{\prime n}(\bigsqcup \mathfrak U_i, \mathcal F)$. Rewrite the supremum to $\top$ using the cover hypothesis, then transport across the whole-space bridge.
788	\end{proof}
