915	\subsection{Affine Čech-acyclic cover carrier}
916	
917	The predicate $\IsAffineHModuleVanishing$ (Definition~\ref{def:Scheme_IsAffineHModuleVanishing}) requires vanishing on every affine open. To instantiate it from Čech data, we introduce a carrier class that bundles the existence of a suitable cover per affine open.
918	
919	\begin{definition}\leanok
920	[Affine Čech-acyclic cover carrier]
921	  \label{def:Scheme_HasAffineCechAcyclicCover}
922	  \lean{AlgebraicGeometry.Scheme.HasAffineCechAcyclicCover}
923	  \uses{def:Scheme_IsCechAcyclicCover, def:Scheme_HasCechToHModuleIso}
924	  For every affine open $U$, there exists an indexed cover $\mathfrak U$ with $\bigsqcup \mathfrak U_i = U$ that is Čech-acyclic and carries a comparison isomorphism.
925	\end{definition}
926	
927	\begin{theorem}\leanok
928	[Producer for $\IsAffineHModuleVanishing$]
929	  \label{thm:Scheme_instIsAffineHModuleVanishing_of_hasAffineCechAcyclicCover}
930	  \lean{AlgebraicGeometry.Scheme.instIsAffineHModuleVanishing_of_hasAffineCechAcyclicCover}
931	  \uses{def:Scheme_HasAffineCechAcyclicCover, thm:Scheme_subsingleton_HModule_prime_of_hasCechToHModuleIso}
932	  If $\HasAffineCechAcyclicCover$ holds, then $\IsAffineHModuleVanishing$ holds.
933	\end{theorem}
